import{bQ as i,aL as a,u as t,G as h}from"./chunks/framework.D06dwy5q.js";const o=JSON.parse('{"title":"网络诊断与排错","description":"","frontmatter":{},"headers":[],"relativePath":"01.Linux基础/14-网络诊断与排错.md","filePath":"01.Linux基础/14-网络诊断与排错.md","lastUpdated":null}'),e={name:"01.Linux基础/14-网络诊断与排错.md"};function p(n,s,l,d,k,r){return a(),t("div",null,[...s[0]||(s[0]=[h(`<h1 id="网络诊断与排错" tabindex="-1">网络诊断与排错 <a class="header-anchor" href="#网络诊断与排错" aria-label="Permalink to &quot;网络诊断与排错&quot;">​</a></h1><p>网络故障排查按从下往上的顺序收敛：地址→路由→DNS→端口→协议响应→抓包。每步用对应的工具，不跳层、不乱序。</p><h2 id="一、收集基础信息" tabindex="-1">一、收集基础信息 <a class="header-anchor" href="#一、收集基础信息" aria-label="Permalink to &quot;一、收集基础信息&quot;">​</a></h2><p>四个命令，先看本机的网络基本面：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ip</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> addr</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">                 # 网卡有没有 UP、IP 对不对</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ip</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> route</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">                # 默认路由和静态路由是否正确</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cat</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /etc/resolv.conf</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    # DNS 指向哪里</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ss</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -lntp</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">                # 哪些服务在监听哪些端口</span></span></code></pre></div><p>很多问题到这一步就已经暴露出来了，不需要继续往下查。</p><h2 id="二、ping" tabindex="-1">二、ping <a class="header-anchor" href="#二、ping" aria-label="Permalink to &quot;二、ping&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ping</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -c</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 4</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 8.8.8.8</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">           # ping IP</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ping</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -c</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 4</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> example.com</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">       # ping 域名</span></span></code></pre></div><p>能 ping 通 IP 但 ping 不通域名 → DNS 问题。IP 也 ping 不通 → 继续排查路由、防火墙、云安全组。</p><p>ping 用的是 ICMP 协议，有些服务器和网络设备主动禁 ICMP，ping 不通不代表业务端口不通。HTTP、SSH 这类服务还是要直接测试端口。</p><h2 id="三、traceroute-和-mtr" tabindex="-1">三、traceroute 和 mtr <a class="header-anchor" href="#三、traceroute-和-mtr" aria-label="Permalink to &quot;三、traceroute 和 mtr&quot;">​</a></h2><p><code>traceroute</code> 显示数据包经过的路径：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">traceroute</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 8.8.8.8</span></span></code></pre></div><p><code>mtr</code> 是 <code>traceroute</code> + <code>ping</code> 的合体版本，持续统计每一跳的丢包率和延迟：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">mtr</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 8.8.8.8</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">mtr</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -rw</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 8.8.8.8</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">       # -r 报告模式，-w 宽输出，适合截图</span></span></code></pre></div><p>安装：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">yum</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> traceroute</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> mtr</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -y</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">apt</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> traceroute</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> mtr</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -y</span></span></code></pre></div><p>看 mtr 输出时一个容易误判的点：中间某一跳的丢包率很高，不等于是那台路由器有问题。许多路由器限制 ICMP 回复速率或者直接不回复，最终目的地址有没有丢包、延迟是否正常才是关键指标。</p><h2 id="四、curl-测试-http" tabindex="-1">四、curl 测试 HTTP <a class="header-anchor" href="#四、curl-测试-http" aria-label="Permalink to &quot;四、curl 测试 HTTP&quot;">​</a></h2><p>HTTP 层的排查优先用 <code>curl</code>，它是 HTTP 客户端的事实标准。</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -I</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> http://example.com</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">               # 只看响应头</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -v</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> http://example.com</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">               # 看完整的请求-响应过程</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -fsS</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> http://127.0.0.1:8080/healthz</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">   # 静默但保留错误</span></span></code></pre></div><p>常用参数：</p><table tabindex="0"><thead><tr><th>参数</th><th>作用</th></tr></thead><tbody><tr><td><code>-I</code></td><td>HEAD 请求，只看响应头</td></tr><tr><td><code>-v</code></td><td>显示连接过程（DNS 解析、TLS 握手、请求头）</td></tr><tr><td><code>-f</code></td><td>收到 HTTP 4xx/5xx 时将退出码设为失败</td></tr><tr><td><code>-sS</code></td><td><code>-s</code> 静默（去掉进度条），<code>-S</code> 保留错误信息</td></tr><tr><td><code>-L</code></td><td>自动跟随重定向</td></tr><tr><td><code>-k</code></td><td>忽略 TLS 证书校验（测试时用，生产脚本避免）</td></tr></tbody></table><p>脚本里健康检查的典型写法：<code>curl -fsS http://127.0.0.1:8080/healthz</code>。失败时有非零退出码，也有错误输出，方便监控和排错。</p><h2 id="五、dns-诊断" tabindex="-1">五、DNS 诊断 <a class="header-anchor" href="#五、dns-诊断" aria-label="Permalink to &quot;五、DNS 诊断&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">getent</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> hosts</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> example.com</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">         # 走系统 NSS，模拟真实解析路径</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">dig</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> example.com</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">                  # 直接查 DNS</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">dig</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> @8.8.8.8</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> example.com</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">         # 指定 DNS 服务器做对比</span></span></code></pre></div><p>排查 DNS 问题时，需要同时关注两个文件：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cat</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /etc/nsswitch.conf</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">           # 看解析顺序（files 在 dns 前还是后）</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cat</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /etc/resolv.conf</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">             # 看当前 DNS 服务器</span></span></code></pre></div><p><code>/etc/hosts</code> 写死的旧 IP 是 DNS 排查中常见的老问题：&quot;dig 出来已经是新 IP 了，但应用层还是连旧 IP&quot;——就是因为 nsswitch 里 files 排在 dns 前面。</p><h2 id="六、ss-查看连接" tabindex="-1">六、ss 查看连接 <a class="header-anchor" href="#六、ss-查看连接" aria-label="Permalink to &quot;六、ss 查看连接&quot;">​</a></h2><p>本机监听的查看：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ss</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -lntp</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">               # -l 监听，-n 不解析名称，-t TCP，-p 进程</span></span></code></pre></div><p>查看所有 TCP 连接：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ss</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -antp</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> grep</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;:3306&#39;</span></span></code></pre></div><p>TCP 连接状态：</p><table tabindex="0"><thead><tr><th>状态</th><th>含义</th></tr></thead><tbody><tr><td>LISTEN</td><td>正在监听，等待客户端连接</td></tr><tr><td>ESTAB</td><td>连接已建立，正在传输数据</td></tr><tr><td>TIME-WAIT</td><td>连接已关闭，等待残留数据包超时</td></tr><tr><td>SYN-SENT</td><td>客户端已发 SYN，等待服务端回应</td></tr><tr><td>SYN-RECV</td><td>服务端收到 SYN，等待客户端 ACK</td></tr></tbody></table><p>大量 <code>SYN-SENT</code> → 客户端发出的 SYN 没收到回应（对端不可达或被拦截）。大量 <code>TIME-WAIT</code> 不一定是问题——它是 TCP 的正常收尾状态。但如果同时出现端口耗尽（高并发短连接场景），才需要考虑调整内核参数或改连接方式。</p><h2 id="七、tcpdump-抓包" tabindex="-1">七、tcpdump 抓包 <a class="header-anchor" href="#七、tcpdump-抓包" aria-label="Permalink to &quot;七、tcpdump 抓包&quot;">​</a></h2><p>抓包是最后一层手段，用之前先尽量把问题范围缩小。</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">tcpdump</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -i</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> eth0</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> host</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 10.0.0.1</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">                    # 只看与 10.0.0.1 通信的包</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">tcpdump</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -i</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> eth0</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> port</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 80</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">                           # 只看 80 端口的包</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">tcpdump</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -i</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> eth0</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> host</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 10.0.0.1</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> and</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> port</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 443</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">        # 两个条件取交</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">tcpdump</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -i</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> eth0</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -w</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /tmp/debug.pcap</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> host</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 10.0.0.1</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  # 保存到文件</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">tcpdump</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -i</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> eth0</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -c</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 100</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> port</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 53</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">                    # 抓 100 个包后停止</span></span></code></pre></div><p>生产环境抓包要控制过滤条件和抓包时长。不设过滤的全量抓包会快速生成大文件，也可能捕获业务敏感数据。</p><h2 id="八、排错的统一顺序" tabindex="-1">八、排错的统一顺序 <a class="header-anchor" href="#八、排错的统一顺序" aria-label="Permalink to &quot;八、排错的统一顺序&quot;">​</a></h2><table tabindex="0"><thead><tr><th>步骤</th><th>命令</th><th>要确认的</th></tr></thead><tbody><tr><td>本机地址</td><td><code>ip addr</code></td><td>网卡是否 UP、IP 和掩码是否对</td></tr><tr><td>路由</td><td><code>ip route</code></td><td>默认路由是否存在、是否有冲突路由</td></tr><tr><td>DNS</td><td><code>getent hosts &lt;domain&gt;</code></td><td>域名能否解析、解析结果对不对</td></tr><tr><td>本机端口</td><td><code>ss -lntp</code></td><td>服务是否在监听、监听地址对不对</td></tr><tr><td>本机访问</td><td><code>curl http://127.0.0.1:port</code></td><td>回环能否访问</td></tr><tr><td>远端访问</td><td><code>curl http://server:port</code></td><td>跨网络能否访问</td></tr><tr><td>抓包</td><td><code>tcpdump</code></td><td>数据包实际在哪里断了</td></tr></tbody></table><p>两个诊断结果最有用：</p><ul><li><code>Connection refused</code> → 已到达目标机器，但目标端口没有服务在监听（或被主动拒绝）</li><li><code>Connection timed out</code> → 中间网络、防火墙、安全组、回包路径某个环节有问题</li></ul><p>把这两种情况分清楚，后续方向就不会跑偏。</p>`,46)])])}const F=i(e,[["render",p]]);export{o as __pageData,F as default};
